import{_ as e,o as t,c as a,Q as o}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"Per-Design BoM","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reports/designs_bom/index.md","filePath":"guide/reports/designs_bom/index.md","lastUpdated":1773939149000}'),r={name:"guide/reports/designs_bom/index.md"},s=o('<h1 id="per-design-bom" tabindex="-1">Per-Design BoM <a class="header-anchor" href="#per-design-bom" aria-label="Permalink to &quot;Per-Design BoM&quot;">​</a></h1><p>The Per-Design Bill of Materials generates one PDF per unique design. If multiple assemblies share the same design, only one BoM is created for that design (deduplicated).</p><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><ul><li><strong>Format:</strong> ZIP containing one PDF per unique design</li><li><strong>Content:</strong> Complete parts list for each design, including all branches (wood, plates, accessories).</li></ul><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><table><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Cover page</strong></td><td>Include a title page with project and design information.</td></tr><tr><td><strong>Designs summary</strong></td><td>Add a summary table of all included designs.</td></tr><tr><td><strong>Show profile side drawings</strong></td><td>Include wood profile cross-section drawings.</td></tr><tr><td><strong>Show plate drawings</strong></td><td>Include plate drawings.</td></tr><tr><td><strong>Table style</strong></td><td>Choose between &quot;Extended tables&quot; or &quot;Classic tables&quot; layout.</td></tr><tr><td><strong>Attach to viewer</strong></td><td>Link the generated PDF to the assembly in the 3D Viewer.</td></tr></tbody></table><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><p>This report type is ideal when you want a complete BoM per design type rather than per physical assembly. Useful for purchasing and material planning where quantities are calculated per design variant.</p>',8),n=[s];function i(d,l,h,p,g,u){return t(),a("div",null,n)}const _=e(r,[["render",i]]);export{m as __pageData,_ as default};
